import{_ as a}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as t,o,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Cloudflare API Token の設定","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Safety/cloudflare-api-token.md","filePath":"ja-JP/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),r={name:"ja-JP/Safety/cloudflare-api-token.md"};function i(n,e,h,p,c,f){return o(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="cloudflare-api-token-の設定" tabindex="-1">Cloudflare API Token の設定 <a class="header-anchor" href="#cloudflare-api-token-の設定" aria-label="Permalink to &quot;Cloudflare API Token の設定&quot;">​</a></h1><p>ImgBed の一部機能では、Cloudflare API Token が必要です。たとえば R2、Workers、D1、KV などの Cloudflare リソースを操作するときに使います。</p><h2 id="用意するもの" tabindex="-1">用意するもの <a class="header-anchor" href="#用意するもの" aria-label="Permalink to &quot;用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Cloudflare アカウント</td><td>API Token を作成します</td></tr><tr><td>対象アカウント ID</td><td>R2 や Workers などの操作対象</td></tr><tr><td>必要な権限</td><td>使う機能に応じて最小限の権限を付与します</td></tr></tbody></table><h2 id="api-token-を作成する" tabindex="-1">API Token を作成する <a class="header-anchor" href="#api-token-を作成する" aria-label="Permalink to &quot;API Token を作成する&quot;">​</a></h2><ol><li>Cloudflare Dashboard にログインします。</li><li>右上のプロフィールから <code>My Profile</code> を開きます。</li><li><code>API Tokens</code> を開きます。</li><li><code>Create Token</code> をクリックします。</li><li>必要な権限を選びます。</li><li>対象アカウントまたはゾーンを指定します。</li><li>作成後に表示される Token をコピーします。</li></ol><p>![Cloudflare API Token](../../image/Safety/cloudflare api token截图.png)</p><p>Token は作成直後しか表示されない場合があります。必ず安全な場所に控えてください。</p><h2 id="グローバル-api-キーとの違い" tabindex="-1">グローバル API キーとの違い <a class="header-anchor" href="#グローバル-api-キーとの違い" aria-label="Permalink to &quot;グローバル API キーとの違い&quot;">​</a></h2><p>Cloudflare には Global API Key もありますが、通常は API Token の利用をおすすめします。</p><table tabindex="0"><thead><tr><th>種類</th><th>特徴</th></tr></thead><tbody><tr><td>API Token</td><td>権限と対象範囲を限定できます</td></tr><tr><td>Global API Key</td><td>アカウント全体に強い権限を持ちます</td></tr></tbody></table><p>必要最小限の権限だけを与えた API Token の方が、運用上安全です。</p><p><img src="'+a+'" alt="グローバルキー確認" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>ImgBed の設定画面で Cloudflare API Token を入力し、保存します。</p><p>保存後、関連機能で接続確認や容量確認を行い、Token が正しく動作するか確認してください。</p><h2 id="運用の注意" tabindex="-1">運用の注意 <a class="header-anchor" href="#運用の注意" aria-label="Permalink to &quot;運用の注意&quot;">​</a></h2><ul><li>Token は公開リポジトリやフロントエンドコードへ直接書かないでください。</li><li>権限は必要な範囲に絞ります。</li><li>不要になった Token は Cloudflare 側で削除します。</li><li>漏えいした可能性がある場合は、すぐに失効させて作り直します。</li></ul>',18)])])}const P=t(r,[["render",i]]);export{u as __pageData,P as default};
